import { Button, Checkbox, Grid, Typography } from '@material-ui/core';
import { CloudDownload, Refresh } from '@material-ui/icons';
import CreateIcon from '@material-ui/icons/Create';
import { useRequest } from 'ahooks';
import fileDownload from 'js-file-download';
import { useSnackbar } from 'notistack';
import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import styled from 'styled-components';

import { useAPI, useHttpResource } from '../api/API';
import { useAppLanguage } from '../i18n/hooks';

import { ExportToFileDialog } from './ExportToFileDialog';
import TICK from '../assets/icons/tick.png';
import CROSS from '../assets/icons/cross.png';
import ProductModal from './ProductModal';

export function ProductCatalogDataTable(props) {
  const { isLoading, productList, setSelectedID, selectedID } = props;
  // console.log('table List', productList);

  const { t } = useTranslation();
  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false);

  const api = useAPI();

  const [currentLanguage] = useAppLanguage();
  const { enqueueSnackbar } = useSnackbar();

  const exportRequest = useRequest(
    (filename) =>
      api.requestJSON(
        'POST',
        props.export_url || `${props.resource_url}export/`,
        {
          data: {
            filename,
            file_type: 'csv',
          },
        }
      ),
    {
      manual: true,
      onSuccess: (data, [filename]) => {
        fileDownload(data, `${filename}.csv`);
      },
      onError: (e) => {
        if (e) {
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          const message = e.message;

          enqueueSnackbar(message[currentLanguage], {
            variant: 'error',
            preventDuplicate: true,
            key: message[currentLanguage],
          });
        }
      },
    }
  );
  const results = useHttpResource(props.resource_url);

  return (
    <>
      <ExportToFileDialog
        open={isExportDialogOpen}
        isLoading={exportRequest.loading}
        onClose={() => {
          setIsExportDialogOpen(false);
        }}
        onSave={(filename) => {
          exportRequest.run(filename);
        }}
      />

      <Grid container direction="column" spacing={2} wrap="nowrap">
        <Grid item container spacing={2} alignItems="center" justify="flex-end">
          {/* <Grid item container sm spacing={2} alignItems="center">
            <Button variant="outlined">Skin Products</Button>
            <Button variant="outlined">Hair Products</Button>
            <Button variant="outlined">Nail Products</Button>
          </Grid> */}

          {props.toolbar?.export && (
            <Grid item>
              <Grid container spacing={2}>
                <Grid item>
                  <Button
                    onClick={() => {
                      results.revalidate();
                    }}
                    disabled={results.isValidating}
                    variant="outlined"
                    startIcon={<Refresh />}
                  >
                    {t('datatable.refresh')}
                  </Button>
                </Grid>
                <Grid item>
                  <Button
                    color="primary"
                    variant="outlined"
                    disabled={results.isValidating}
                    startIcon={<CloudDownload />}
                    onClick={() => {
                      setIsExportDialogOpen(true);
                    }}
                  >
                    {t('datatable.export')}
                  </Button>
                </Grid>
              </Grid>
            </Grid>
          )}
        </Grid>

        <TableBox>
          <TableHeader>
            <Checkbox color="primary" />
            <p className="id">PID</p>
            {/* <p className="image">Image</p> */}
            <p className="product-name">Product Name</p>
            {/* <p className="price">Description</p> */}
            <p className="brand">Link</p>
            <p className="status">Type</p>
            <p className="modification">Modification</p>
          </TableHeader>
          {isLoading && (
            <Typography
              variant="h4"
              style={{ textAlign: 'center', marginTop: 50 }}
            >
              Loading ...
            </Typography>
          )}
          {!isLoading && productList?.length === 0 && (
            <Typography
              variant="h6"
              style={{ textAlign: 'center', marginTop: 50 }}
            >
              {' '}
              No Data.
            </Typography>
          )}
          <TableContaier>
            {!isLoading &&
              productList &&
              productList.map((item) => (
                <div className="single-table-item">
                  <Checkbox
                    color="primary"
                    checked={selectedID === item.id ? true : false}
                    onClick={() => setSelectedID(item.id)}
                  />
                  <p className="id">{item.id}</p>
                  {/* <div className="image-box">
                    <img className="image" src="" alt="product" />
                  </div> */}
                  <p className="product-name">{item.name}</p>
                  {/* <p className="brand">{item.description}</p> */}
                  <a href={item.link} target="blank" className="brand">
                    {item.link}
                  </a>
                  <p className="price" style={{ textAlign: 'center' }}>
                    {item.product_type}
                  </p>
                  {/* <div className="status-box">
                    <Button
                      variant="contained"
                      style={{ background: '#A2F200', borderRadius: 20 }}
                    >
                      <img src={TICK} alt="V" />
                    </Button>
                    <Button
                      variant="contained"
                      style={{ background: '#FF0000', borderRadius: 20 }}
                    >
                      <img src={CROSS} alt="X" />
                    </Button>
                  </div> */}
                  <div className="edit-btn">
                    <ProductModal
                      title="Edit"
                      // setSelectedItem={setSelectedItem}
                      item={item}
                    />
                  </div>
                </div>
              ))}
          </TableContaier>
        </TableBox>
      </Grid>
    </>
  );
}

const TableBox = styled.div`
  border: 1px solid #999;
  border-radius: 5px;
  height: 650px;
  overflow: auto;
`;
const TableHeader = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 30px;
  position: sticky;
  top: 0px;
  background: #fff;
  z-index: 1;
  border-bottom: 1px solid #707070;
  p {
    font-size: 18px;
    font-weight: 600;
    color: #707070;
  }
  .id {
    width: 10%;
  }
  .image {
    width: 15%;
  }
  .product-name {
    width: 25%;
  }
  .price {
    width: 25%;
  }
  .brand {
    width: 25%;
  }
  .status {
    width: 25%;
    text-align: center;
  }
  .modification {
    width: 10%;
  }
`;

const TableContaier = styled.div`
  .single-table-item {
    border-bottom: 1px solid #999;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0px 30px;

    .id {
      width: 10%;
    }
    .image-box {
      width: 15%;
      /* width: 125px; */
      height: 90px;
      margin: 5px 0px;
      border: 1px solid #000;
    }
    .image {
    }
    .product-name {
      width: 25%;
    }
    .price {
      width: 25%;
    }
    .brand {
      width: 25%;
      overflow: hidden;
    }
    .status-box {
      width: 15%;
      display: flex;
      align-items: center;
      justify-content: space-around;
    }
    .edit-btn {
      width: 10%;
    }
  }
`;
